t.script:
document.addEventListener('DOMContentLoaded', function() {
    console.log("[Portal Digitalizacion] Inicializando Formulario...");

    const proyectoId = document.getElementById('proyecto_id').value;
    const inputFecha = document.getElementById('inputFecha');
    const tbody = document.getElementById('tbody-registros');
    const btnAgregarFila = document.getElementById('btn-agregar-fila');
    const btnGuardar = document.getElementById('btn-guardar-registros');

    // Parsear Data JSON inyectada por el Controller (Evita Fetch extra)
    const etapas = JSON.parse(document.getElementById('etapas_data').value || '[]');
    const miembros = JSON.parse(document.getElementById('miembros_data').value || '[]');
    const escaneres = JSON.parse(document.getElementById('escaneres_data').value || '[]');

    // ── Mapeo de reglas de visibilidad según Etapa (DASHBOARD_SPEC.md / Diccionario de Datos) ──
    const reglasEtapa = {
        'limpieza': ['col-caja', 'col-cantidad-cajas', 'col-expedientes', 'col-folios'],
        'ordenado': ['col-caja', 'col-cantidad-cajas', 'col-expedientes', 'col-folios'],
        'digitalizado': ['col-folios', 'col-escaneos', 'col-escaner']
    };

    // Si no hay miembros, advertencia
    if(miembros.length === 0) {
        tbody.innerHTML = `<tr><td colspan="9" class="text-center text-danger py-4">
            <i class="fa fa-exclamation-triangle mr-2"></i> 
            No hay digitalizadores agregados a este proyecto. 
            Ve a 'Gestionar Equipo' para agregarlos primero.
            </td></tr>`;
        btnAgregarFila.disabled = true;
        btnGuardar.disabled = true;
        return;
    }

    let rowCounter = 0;

    function crearHTMLFila(idFila) {
        // Options Miembros
        let opcionesMiembros = `<option value="">Seleccione...</option>`;
        miembros.forEach(m => {
            opcionesMiembros += `<option value="${m.id}">${m.name}</option>`;
        });

        // Options Etapas
        let opcionesEtapas = `<option value="">Seleccione...</option>`;
        etapas.forEach(e => {
            opcionesEtapas += `<option value="${e.id}" data-name="${e.name.toLowerCase()}">${e.name}</option>`;
        });

        // Options Escáner (Multiple idealmente, pero para simplificar UI web, listado simple)
        let opcionesEscaner = `<option value="">No aplica</option>`;
        escaneres.forEach(eq => {
            opcionesEscaner += `<option value="${eq.id}">${eq.name}</option>`;
        });

        return `
            <tr id="fila-${idFila}" class="fila-registro">
                <td>
                    <select class="form-select input-miembro" required>
                        ${opcionesMiembros}
                    </select>
                </td>
                <td>
                    <select class="form-select input-etapa" required onchange="actualizarCamposFila(${idFila})">
                        ${opcionesEtapas}
                    </select>
                </td>
                <td class="td-caja"><input type="text" class="form-control input-caja" placeholder="Ej. A-1"/></td>
                <td class="td-cantidad-cajas"><input type="number" class="form-control input-cant-cajas" min="0"/></td>
                <td class="td-expedientes"><input type="number" class="form-control input-expedientes" min="0"/></td>
                <td class="td-folios"><input type="number" class="form-control input-folios" min="0"/></td>
                <td class="td-escaneos"><input type="number" class="form-control input-escaneos" min="0"/></td>
                <td class="td-escaner">
                    <select class="form-select input-escaner">
                        ${opcionesEscaner}
                    </select>
                </td>
                <td class="text-center">
                    <button type="button" class="btn btn-sm btn-outline-danger btn-eliminar" onclick="eliminarFila(${idFila})">
                        <i class="oi oi-trash"></i>
                    </button>
                </td>
            </tr>
        `;
    }

    // --- Agregar Fila Base Inicial ---
    agregarFila();

    btnAgregarFila.addEventListener('click', function() {
        agregarFila();
    });

    function agregarFila() {
        rowCounter++;
        tbody.insertAdjacentHTML('beforeend', crearHTMLFila(rowCounter));
        actualizarCamposFila(rowCounter); // Deshabilitar todo hasta que elija etapa
    }

    window.eliminarFila = function(idFila) {
        const fila = document.getElementById(`fila-${idFila}`);
        if (fila) fila.remove();
        // Si eliminó todas, agregar una vacía
        if (document.querySelectorAll('.fila-registro').length === 0) {
            agregarFila();
        }
    };

    window.actualizarCamposFila = function(idFila) {
        const fila = document.getElementById(`fila-${idFila}`);
        if (!fila) return;

        const selectEtapa = fila.querySelector('.input-etapa');
        const nombreEtapa = selectEtapa.options[selectEtapa.selectedIndex].getAttribute('data-name') || '';

        // Reset visual state (bloquear por default)
        const cells = fila.querySelectorAll('td');
        cells.forEach(c => {
            if(c.className.includes('td-')) {
                c.classList.add('col-deshabilitada');
                const input = c.querySelector('input, select');
                if(input) { input.disabled = true; input.value = ''; }
            }
        });

        // Habilitar según regla dinámica
        for (const [key, clases] of Object.entries(reglasEtapa)) {
            if (nombreEtapa.includes(key)) {
                clases.forEach(clase => {
                    // ejemplo: clase = 'col-escaneos', buscar td-escaneos
                    const claseTd = 'td-' + clase.split('-')[1] + (clase.split('-')[2] ? '-' + clase.split('-')[2] : '');

                    const tdTarget = fila.querySelector('.' + claseTd);
                    if(tdTarget) {
                        tdTarget.classList.remove('col-deshabilitada');
                        const input = tdTarget.querySelector('input, select');
                        if(input) input.disabled = false;
                    }
                });
                break;
            }
        }
    };

    // --- Guardado de Registros (API) ---
    btnGuardar.addEventListener('click', function() {

        const filasTR = document.querySelectorAll('.fila-registro');
        let payloadFilas = [];
        let isValid = true;

        filasTR.forEach((tr, index) => {
            const miembroId = tr.querySelector('.input-miembro').value;
            const etapaId = tr.querySelector('.input-etapa').value;

            if(!miembroId || !etapaId) {
                isValid = false;
                tr.style.border = "2px solid red";
                return;
            } else {
                tr.style.border = "none";
            }

            // Construir objeto para JSON-RPC alineado al Diccionario de Datos del Spec
            let filaObj = {
                miembro_id: parseInt(miembroId),
                etapa_id: parseInt(etapaId),
                no_caja: tr.querySelector('.input-caja').value || "",
                cantidad_cajas: parseInt(tr.querySelector('.input-cant-cajas').value) || 0,
                no_expedientes: parseInt(tr.querySelector('.input-expedientes').value) || 0,
                total_folios: parseInt(tr.querySelector('.input-folios').value) || 0,
                total_escaneos: parseInt(tr.querySelector('.input-escaneos').value) || 0,
            };

            const escanerId = tr.querySelector('.input-escaner').value;
            if(escanerId) {
                filaObj.tipo_escaner_ids = [parseInt(escanerId)];
            }

            payloadFilas.push(filaObj);
        });

        if(!isValid) {
            alert("Faltan campos obligatorios (Digitalizador o Etapa) en algunas filas.");
            return;
        }

        if(payloadFilas.length === 0) return;

        // UI Loading
        btnGuardar.disabled = true;
        document.getElementById('msg-guardando').classList.remove('d-none');
        document.getElementById('msg-exito').classList.add('d-none');
        document.getElementById('msg-advertencias').classList.add('d-none');

        // Enviar via fetch nativo (Odoo 17 — odoo.define/web.rpc deprecated en portal)
        const csrfToken = document.cookie
            .split('; ')
            .find(row => row.startsWith('csrf_token='))
            ?.split('=')[1] || '';

        fetch('/digitalizacion/api/guardar_registros', {
            method: 'POST',
            headers: {
                'Content-Type': 'application/json',
                'X-CSRFToken': csrfToken
            },
            body: JSON.stringify({
                jsonrpc: '2.0',
                method: 'call',
                id: 1,
                params: {
                    proyecto_id: parseInt(proyectoId),
                    fecha: inputFecha.value,
                    filas: payloadFilas
                }
            })
        })
        .then(r => r.json())
        .then(function(data) {
            const result = data.result || {};
            btnGuardar.disabled = false;
            document.getElementById('msg-guardando').classList.add('d-none');

            if (result.status === 'success') {
                document.getElementById('msg-exito').classList.remove('d-none');
                tbody.innerHTML = '';
                agregarFila();
                if (result.advertencias && result.advertencias.length > 0) {
                    mostrarAdvertencia(result.advertencias);
                }
            } else {
                alert('Error del servidor: ' + (result.message || 'Error desconocido'));
            }
        })
        .catch(function(error) {
            btnGuardar.disabled = false;
            document.getElementById('msg-guardando').classList.add('d-none');
            alert('Error critico al contactar el servidor Odoo.');
            console.error(error);
        });
    });

    function mostrarAdvertencia(mensajes) {
        const divAdv = document.getElementById('msg-advertencias');
        divAdv.classList.remove('d-none');
        let ul = '<ul class="mb-0">';
        mensajes.forEach(m => { ul += `<li>${m}</li>`; });
        ul += '</ul>';
        divAdv.innerHTML = `
            <div class="alert alert-warning">
                <strong>Guardado Parcial:</strong> Algunos registros tuvieron problemas:
                ${ul}
            </div>`;
    }

});
